import { html, customElement, property, css, when } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import type { UmbTreeElement, UmbTreeItemModelBase } from '@umbraco-cms/backoffice/tree';
import { FORMS_EMAIL_TEMPLATE_TREE_ALIAS } from '../../section/email-templates/tree/index.js';

const elementName = "forms-email-template-picker-property-editor";
const valuePrefix = "Forms/Emails";

@customElement(elementName)
export class FormsEmailTemplatePickerPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #value: string = "";

  @property({ type: String })
  get value() { return this.#value ?? "" }
  set value(value: string) {
    const oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);
  }

	#onTreeSelectionChange(event: CustomEvent) {
		const target = event.target as UmbTreeElement;
		const selection = target.getSelection();
    if (selection.length > 0) {
      this.value = valuePrefix + selection[0].replace("%25dot%25", ".").replace("%2F", "/");
    } else {
      this.value = "";
    }

    this.dispatchEvent(new CustomEvent('property-value-change'));
	}

  #getSelectionForTree() {
    if (this.value.length === 0) {
      return [];
    }

    return [this.value.replace(valuePrefix, "").replace(".", "%25dot%25").replace("/", "%2F")];
  }

  #getSelectedValueForDisplay() {
    return this.value.replace(valuePrefix + "/", "");
  }

  render() {
    return html`
        ${when(this.value.length > 0,
          () => html`<div>Selected template: <strong>${this.#getSelectedValueForDisplay()}</strong></div>`)}
        <umb-tree
          id="EmailTemplate"
          alias="${FORMS_EMAIL_TEMPLATE_TREE_ALIAS}"
          .props=${{
            hideTreeRoot: false,
            selectionConfiguration: {
              multiple: false,
              selection: this.#getSelectionForTree()
            },
            selectableFilter: (item: UmbTreeItemModelBase) =>
              !item.isFolder,
          }}
          @selection-change=${this.#onTreeSelectionChange}
        ></umb-tree>`;
  }

  static styles = [
		css`

		`,
  ];
}

export default FormsEmailTemplatePickerPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsEmailTemplatePickerPropertyUiElement;
    }
}
